void reserve(size_t new_cap) {
    if (new_cap <= capacity) return;  // No-op if sufficient

    T* new_data = new T[new_cap];  // Allocate larger buffer
    for (size_t i = 0; i < size; ++i) {
        new_data[i] = std::move(data[i]);  // Move existing elements
    }
    delete[] data;
    data = new_data;
    capacity = new_cap;
